import{c as s,Q as n,j as a,m as o}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"GC 进阶","description":"","frontmatter":{},"headers":[],"relativePath":"interpreterLearning/27-GC进阶.md","filePath":"interpreterLearning/27-GC进阶.md","lastUpdated":1778496697000}'),e={name:"interpreterLearning/27-GC进阶.md"};function r(p,t,d,i,l,c){return n(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="gc-进阶" tabindex="-1">GC 进阶 <a class="header-anchor" href="#gc-进阶" aria-label="Permalink to &quot;GC 进阶&quot;">​</a></h1><p>基础 mark-sweep 跑 Mochi 的玩具堆没问题——堆才几 MB,扫一遍微秒级。但 <strong>JVM 跑一个百 GB 堆的服务</strong>:扫一遍要几百毫秒,STW 期间所有线程冻结,<strong>电商秒杀这一秒所有请求超时</strong>。生产语言活不下去基础 mark-sweep。三条优化路线轮番上:<strong>分代假设</strong>(大部分对象朝生暮死,新生代单独管)、<strong>增量</strong>(把一次大 STW 拆成多次小停顿)、<strong>并发</strong>(mutator 和 collector 同时跑)。<strong>三条路都靠写屏障</strong>——一旦 GC 不再独占堆,任何&quot;老对象指新对象&quot;的赋值都得记账。这一篇拆 V8 / JVM / Go 都在走的这条路,<strong>Mochi 永远不上,但你要知道为什么</strong>。</p><blockquote><p>一句话先记住:<strong>分代 + 写屏障 + 增量 / 并发 = 生产 GC 的标配</strong>。Mochi 不上,因为玩具堆几 MB 看不见 STW;上了反而代码上千行。但读 V8 / JVM / Go 源码,<strong>这一篇的概念缺一不可</strong>。</p></blockquote><hr><h2 id="一、基础-mark-sweep-的痛-stw-太长" tabindex="-1">一、基础 mark-sweep 的痛:STW 太长 <a class="header-anchor" href="#一、基础-mark-sweep-的痛-stw-太长" aria-label="Permalink to &quot;一、基础 mark-sweep 的痛:STW 太长&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>堆大小       mark+sweep 时间   STW 影响</span></span>
<span class="line"><span>1 MB         &lt;1 ms             看不见</span></span>
<span class="line"><span>100 MB       ~50 ms            HTTP 抖动一下</span></span>
<span class="line"><span>10 GB        ~5 s              电商整条请求超时</span></span>
<span class="line"><span>100 GB       ~50 s             P99 直接爆炸</span></span></code></pre></div><p><strong>问题本质</strong>:mark 阶段要扫整个对象图,sweep 阶段要扫整个堆——<strong>时间 O(堆大小)</strong>。堆涨 100 倍,GC 慢 100 倍。</p><p>生产语言的优化目标:<strong>STW 与堆大小解耦,做到亚毫秒级</strong>。</p><hr><h2 id="二、分代假设-90-新对象朝生暮死" tabindex="-1">二、分代假设:90% 新对象朝生暮死 <a class="header-anchor" href="#二、分代假设-90-新对象朝生暮死" aria-label="Permalink to &quot;二、分代假设:90% 新对象朝生暮死&quot;">​</a></h2><p><strong>经验数据</strong>(IBM / Sun 在 1990s 测过几乎所有真实程序):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新分配的对象,90%+ 在第一次 GC 时已经死了</span></span>
<span class="line"><span>活过一次 GC 的对象,大概率活很久(配置、缓存、长生命周期对象)</span></span></code></pre></div><p>这就是<strong>弱分代假设</strong>(Weak Generational Hypothesis)。直接推论:<strong>把&quot;新对象&quot;和&quot;老对象&quot;分开管</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  young gen (新生代)                           │</span></span>
<span class="line"><span>│  ├─ eden(分配区)                             │</span></span>
<span class="line"><span>│  └─ survivor 0 / 1(幸存区,半区复制)        │</span></span>
<span class="line"><span>│  → minor GC,频繁但快                         │</span></span>
<span class="line"><span>├──────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  old gen (老生代)                             │</span></span>
<span class="line"><span>│  → major GC,不频繁但慢(整堆 mark-sweep)    │</span></span>
<span class="line"><span>└──────────────────────────────────────────────┘</span></span></code></pre></div><ul><li>minor GC:<strong>只扫新生代</strong>——新生代 90% 是死的,扫完 90% 都释放掉,<strong>根本不碰老生代</strong></li><li>活过 N 次 minor GC 的对象 → <strong>promote</strong>(升代)到老生代</li><li>old gen 的 major GC 才扫整堆,但触发频率低</li></ul><p><strong>收益</strong>:分配快(eden 是 bump pointer)、minor GC 快(扫的范围小)、大头长期对象不重复扫。</p><hr><h2 id="三、写屏障-老对象指向新对象的-小账本" tabindex="-1">三、写屏障:老对象指向新对象的&quot;小账本&quot; <a class="header-anchor" href="#三、写屏障-老对象指向新对象的-小账本" aria-label="Permalink to &quot;三、写屏障:老对象指向新对象的&quot;小账本&quot;&quot;">​</a></h2><p>minor GC 只扫新生代 → 漏掉一件事:<strong>老对象的字段指向新对象</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>old gen           young gen</span></span>
<span class="line"><span>┌─────────┐       ┌─────────┐</span></span>
<span class="line"><span>│ obj_old │──────→│ obj_new │</span></span>
<span class="line"><span>└─────────┘       └─────────┘</span></span></code></pre></div><p>minor GC 从 GC roots 出发,<strong>只走新生代内的引用</strong>——<code>obj_new</code> 没人指(从新生代角度看),<strong>被错误回收</strong>。下次访问 <code>obj_old.field</code> 就是 use-after-free。</p><p><strong>修复</strong>:<strong>每次 <code>obj.field = newObj</code> 都拦截一下</strong>,如果 obj 在老生代且 newObj 在新生代,把 obj 记进&quot;remember set&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>write barrier(obj, field, newObj):</span></span>
<span class="line"><span>  obj.field = newObj</span></span>
<span class="line"><span>  if obj 在 old gen and newObj 在 young gen:</span></span>
<span class="line"><span>    remember_set.add(obj)        // 这个老对象要算作新生代的&quot;额外 root&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>minor GC 时:</span></span>
<span class="line"><span>  扫 GC roots + 扫 remember_set 里的对象 → 新生代就不漏标了</span></span></code></pre></div><p><strong>这就是为什么 Java / JS 的 <code>obj.x = y</code> 不是单条机器指令</strong>——编译器要在背后插一段 write barrier 检查。Go 的 <code>*p = x</code>、JVM 的 <code>putfield</code> 都一样。</p><p>写屏障是有开销的——每次字段写都多几条指令。<strong>HotSpot 用卡表(card table)</strong>:把堆分成 512B 的卡片,只记&quot;哪张卡有跨代引用&quot;,粒度粗但便宜。</p><hr><h2 id="四、增量-gc-把大停顿拆小" tabindex="-1">四、增量 GC:把大停顿拆小 <a class="header-anchor" href="#四、增量-gc-把大停顿拆小" aria-label="Permalink to &quot;四、增量 GC:把大停顿拆小&quot;">​</a></h2><p>分代降低了<strong>频率</strong>,没降低单次老生代 GC 的<strong>时间</strong>。老生代 100GB 还是要扫 100GB。</p><p><strong>增量 GC</strong>:把一次 mark 拆成 N 个小 step,<strong>每个 step 跑几 ms 就让 mutator 跑回去</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>普通 STW:      ████████████████  100 ms 一次</span></span>
<span class="line"><span>增量:          █  █  █  █  █  █  10 ms × 10 次,中间穿插 mutator</span></span></code></pre></div><p>但 mutator 会在 GC 中途改对象图,<strong>会破坏三色不变式</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>出问题的场景:</span></span>
<span class="line"><span>1. GC 已经把 A 染黑(以为孩子都扫过了)</span></span>
<span class="line"><span>2. mutator 把 A.field 改成指向白对象 W(原来没人指 W)</span></span>
<span class="line"><span>3. GC 继续扫,W 永远没机会被染灰 → 错误回收</span></span></code></pre></div><p>修复也靠<strong>写屏障</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>增量 GC 的 write barrier:</span></span>
<span class="line"><span>  mutator 写 black.field = white_obj 时:</span></span>
<span class="line"><span>    把 white_obj 染灰,放进灰集合</span></span>
<span class="line"><span>  (或者把 black 退回灰,重新扫——两种屏障策略)</span></span></code></pre></div><p>经典三色不变式:<strong>强不变式</strong>——黑不指白(任何指向白的引用必须从灰对象出发);<strong>弱不变式</strong>——黑能指白,但每个白对象必须能从某个灰对象可达。两种屏障对应两种维护策略。</p><hr><h2 id="五、并发-gc-mutator-和-collector-同时跑" tabindex="-1">五、并发 GC:mutator 和 collector 同时跑 <a class="header-anchor" href="#五、并发-gc-mutator-和-collector-同时跑" aria-label="Permalink to &quot;五、并发 GC:mutator 和 collector 同时跑&quot;">​</a></h2><p>增量是<strong>时间维度</strong>拆分——mutator 和 GC 轮流跑,只用一核。<strong>并发</strong>是<strong>空间维度</strong>拆分:mutator 在 N 个核上跑业务,GC 在另外几个核上扫堆,<strong>真正同时</strong>。</p><p>复杂度更高:三色不变式要在多线程下用原子操作 + 写屏障维护。Go 用<strong>混合写屏障</strong>(Dijkstra + Yuasa 的组合),把 STW 控制在<strong>亚毫秒</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Go GC 的 STW 阶段(整个 GC 周期):</span></span>
<span class="line"><span>  1. STW: 启动准备(&lt;1 ms)</span></span>
<span class="line"><span>  2. 并发标记(几百 ms,但 mutator 跑着)</span></span>
<span class="line"><span>  3. STW: 标记终止(&lt;1 ms)</span></span>
<span class="line"><span>  4. 并发清扫(mutator 跑着)</span></span></code></pre></div><p><strong>关键</strong>:即使堆几十 GB,STW 也是亚毫秒——<strong>与堆大小解耦</strong>。</p><hr><h2 id="六、go-v8-jvm-怎么走的" tabindex="-1">六、Go / V8 / JVM 怎么走的 <a class="header-anchor" href="#六、go-v8-jvm-怎么走的" aria-label="Permalink to &quot;六、Go / V8 / JVM 怎么走的&quot;">​</a></h2><table tabindex="0"><thead><tr><th>语言</th><th>分代</th><th>增量</th><th>并发</th><th>写屏障</th><th>典型 STW</th></tr></thead><tbody><tr><td>Mochi</td><td>无</td><td>无</td><td>无</td><td>无</td><td>全堆扫</td></tr><tr><td>CPython</td><td>无(refcount 主)+ cycle</td><td>无</td><td>无</td><td>无</td><td>取决于 cycle 大小</td></tr><tr><td>Lua 5.1</td><td>无</td><td>增量</td><td>无</td><td>有</td><td>几 ms</td></tr><tr><td>Lua 5.4</td><td>有</td><td>增量</td><td>无</td><td>有</td><td>几 ms</td></tr><tr><td>V8 (Orinoco)</td><td>有 (young/old)</td><td>增量</td><td>并发 mark+sweep</td><td>有</td><td>亚 ms</td></tr><tr><td>HotSpot G1</td><td>有(分区伪分代)</td><td>增量</td><td>并发 mark</td><td>有</td><td>10-200 ms</td></tr><tr><td>HotSpot ZGC</td><td>无(着色指针)</td><td>-</td><td>全并发</td><td>有(读屏障)</td><td>&lt;1 ms,堆 16TB</td></tr><tr><td>Go</td><td>无(只有一代)</td><td>增量</td><td>并发</td><td>混合</td><td>&lt;0.5 ms</td></tr></tbody></table><p>注意几个反直觉的点:</p><ul><li><strong>Go 没分代</strong>——Go 团队压测发现,<strong>逃逸分析 + 栈分配</strong>已经把&quot;短命对象&quot;挡在堆外了,堆上的对象本来就长命,<strong>分代收益有限</strong></li><li><strong>ZGC 没分代</strong>(早期版本)——靠<strong>着色指针</strong>(在地址高位塞 mark 信息)+ <strong>读屏障</strong>做并发,堆 16TB 都能 &lt;1 ms STW</li><li><strong>V8 用半空间复制</strong>(Cheney 算法)做 young GC——young gen 死得太干净,<strong>复制 10% 活的比标记清扫整个 young 还快</strong></li></ul><hr><h2 id="七、为什么-mochi-永远不上" tabindex="-1">七、为什么 Mochi 永远不上 <a class="header-anchor" href="#七、为什么-mochi-永远不上" aria-label="Permalink to &quot;七、为什么 Mochi 永远不上&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优化</th><th>收益(玩具堆)</th><th>代码量</th><th>性价比</th></tr></thead><tbody><tr><td>分代</td><td>几乎无(GC 本来就快)</td><td>+500 行</td><td>负</td></tr><tr><td>写屏障</td><td>无</td><td>+200 行(且每次字段写多开销)</td><td>负</td></tr><tr><td>增量</td><td>无</td><td>+300 行(整个调度循环要重写)</td><td>负</td></tr><tr><td>并发</td><td>无(Mochi 单线程)</td><td>+1000 行</td><td>负</td></tr></tbody></table><p><strong>结论</strong>:玩具语言上这些纯属自虐。Mochi 的 50 行 mark-sweep 跑 100 KB 堆,<strong>STW 几十微秒</strong>,看不见。Mochi 永远只做基础 GC——读者把这一篇当&quot;工业级 GC 路线图&quot;,<strong>实际去读 V8 / Go 源码就有地图了</strong>。</p><hr><h2 id="八、rc-tracing-混合-cpython-的折衷" tabindex="-1">八、RC + tracing 混合:CPython 的折衷 <a class="header-anchor" href="#八、rc-tracing-混合-cpython-的折衷" aria-label="Permalink to &quot;八、RC + tracing 混合:CPython 的折衷&quot;">​</a></h2><p><strong>CPython 是有趣的反例</strong>:主力 refcount(每次赋值 <code>++</code>/<code>--</code>),周期性跑 tracing(<code>gc</code> 模块)只为了打破循环引用:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>对象的生命:</span></span>
<span class="line"><span>  创建时 refcount = 1</span></span>
<span class="line"><span>  每次赋值给变量    → refcount++</span></span>
<span class="line"><span>  变量离开作用域    → refcount--</span></span>
<span class="line"><span>  refcount == 0     → 立即释放(递归 decref)</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>gc.collect() 周期触发:</span></span>
<span class="line"><span>  只扫&quot;可能成环的容器对象&quot;(list/dict/set/instance)</span></span>
<span class="line"><span>  用 tracing 检测无外部引用的循环,释放整个环</span></span></code></pre></div><p><strong>为什么 CPython 这么选</strong>:1989 年的代码,refcount 是当时唯一现实方案;且 Python 的 <code>with</code> / <code>__del__</code> 语义假设<strong>对象死后立即调析构</strong>,纯 tracing 做不到这点。代价:<strong>GIL 拆不掉</strong>(refcount 不能无锁多线程),<strong>整个 PEP 703 移除 GIL 都在解决这个</strong>。</p><hr><h2 id="九、源码指针" tabindex="-1">九、源码指针 <a class="header-anchor" href="#九、源码指针" aria-label="Permalink to &quot;九、源码指针&quot;">​</a></h2><ul><li><strong>Go</strong>: <code>src/runtime/mgc.go</code> 文件头注释 200 行——直接讲三色 + 混合屏障的实现;<code>src/runtime/mgcmark.go</code> 看具体 mark 函数</li><li><strong>V8</strong>: <code>src/heap/</code> 整个目录,主要看 <code>mark-compact.cc</code>(主 GC)和 <code>scavenger.cc</code>(young GC)</li><li><strong>HotSpot ZGC</strong>: 论文 <em>&quot;The Z Garbage Collector&quot;</em>(Oracle 2018),源码在 <code>src/hotspot/share/gc/z/</code></li><li><strong>HotSpot G1</strong>: 论文 <em>&quot;Garbage-First Garbage Collection&quot;</em>(2004)+ <code>src/hotspot/share/gc/g1/</code></li><li><strong>Lua 5.4 分代</strong>: <code>src/lgc.c</code> 里 <code>genstep</code> 系列函数,~200 行实现了完整分代</li><li><strong>Crafting Interpreters</strong>: <strong>没讲分代 / 并发</strong>——和 Mochi 一样选了边界,作者明说&quot;留给读者&quot;</li></ul><hr><p>下一篇:<code>28-JIT心智.md</code>,讲清楚为什么字节码 VM 还不够快、模板 JIT / 方法 JIT / Tracing JIT 三种姿态、<strong>V8 Ignition + TurboFan 怎么协作</strong>、为什么 PyPy 比 CPython 快几倍但 CPython 3.13 也在追赶。</p>`,60)])])}const u=s(e,[["render",r]]);export{h as __pageData,u as default};
